    /// Text to send (newline appended automatically)
    text: String,
}

#[derive(Debug, Subcommand)]
enum BookmarkCommand {
    Add(BookmarkAddArgs),
    List,
    Remove(BookmarkRef),
}

#[derive(Debug, Args)]
struct BookmarkAddArgs {
