use gpui::*;
use dellij_core::{Workspace, WorkspaceStatus};

struct MobileApp {
    workspaces: Vec<Workspace>,
}

impl MobileApp {
    fn new(_cx: &mut Context<Self>) -> Self {
        Self {
            workspaces: Vec::new(),
        }
    }
}

struct HomeView {
    app: Model<MobileApp>,
}

impl HomeView {
    fn new(app: Model<MobileApp>, _cx: &mut ViewContext<Self>) -> Self {
        Self { app }
    }
}

impl Render for HomeView {
    fn render(&mut self, cx: &mut ViewContext<Self>) -> impl IntoElement {
        let app = self.app.read(cx);

        div()
            .flex()
            .flex_col()
            .w_full()
            .h_full()
            .bg(rgb(0x1e1e2e))
            .child(
                div()
                    .h(px(60.))
                    .flex()
                    .items_center()
                    .justify_center()
                    .border_b_1()
                    .border_color(rgb(0x313244))
                    .child(
                        div()
                            .text_color(rgb(0xcba6f7))
                            .font_weight(FontWeight::BOLD)
                            .text_lg()
                            .child("dellij mobile")
                    )
            )
            .child(
                div()
                    .flex_1()
                    .overflow_y_scroll()
                    .children(app.workspaces.iter().map(|ws| {
                        self.render_workspace_item(ws, cx)
                    }))
            )
            .child(
                div()
                    .h(px(70.))
                    .bg(rgb(0x181825))
                    .flex()
                    .flex_row()
                    .items_center()
                    .justify_around()
                    .child(self.render_nav_item("⌂", "Home", true))
                    .child(self.render_nav_item("⚠", "Alerts", false))
                    .child(self.render_nav_item("⚙", "Settings", false))
            )
    }
}

impl HomeView {
    fn render_workspace_item(&self, ws: &Workspace, _cx: &mut ViewContext<Self>) -> impl IntoElement {
        div()
            .flex()
            .flex_row()
            .items_center()
            .p_4()
            .border_b_1()
            .border_color(rgb(0x313244))
            .child(
                div()
                    .w(px(12.))
                    .h(px(12.))
                    .rounded_full()
                    .bg(self.status_color(ws.status))
            )
            .child(
                div()
                    .flex_col()
                    .ml_4()
                    .child(
                        div()
                            .text_color(rgb(0xcdd6f4))
                            .font_weight(FontWeight::SEMIBOLD)
                            .child(ws.slug.clone())
                    )
                    .child(
                        div()
                            .text_color(rgb(0xa6adc8))
                            .text_xs()
                            .child(format!("{} • {}", ws.agent, ws.branch_name))
                    )
            )
    }

    fn render_nav_item(&self, icon: &'static str, label: &'static str, active: bool) -> impl IntoElement {
        div()
            .flex()
            .flex_col()
            .items_center()
            .child(
                div()
                    .text_xl()
                    .text_color(if active { rgb(0xcba6f7) } else { rgb(0x6c7086) })
                    .child(icon)
            )
            .child(
                div()
                    .text_xs()
                    .text_color(if active { rgb(0xcba6f7) } else { rgb(0x6c7086) })
                    .child(label)
            )
    }

    fn status_color(&self, status: WorkspaceStatus) -> Rgb {
        match status {
            WorkspaceStatus::Working => rgb(0x89b4fa), // Blue
            WorkspaceStatus::Blocked => rgb(0xf9e2af), // Yellow
            WorkspaceStatus::Error   => rgb(0xf38ba8), // Red
            WorkspaceStatus::Done    => rgb(0xa6e3a1), // Green
        }
    }
}

fn main() {
    App::new().run(|cx: &mut AppContext| {
        let app_model = cx.new_model(|cx| MobileApp::new(cx));
        cx.open_window(WindowOptions::default(), |cx| {
            cx.new_view(|cx| HomeView::new(app_model, cx))
        });
    });
}

Web search results for "gpui-mobile rust main function async App run example":

To run a GPUI application with async support (especially for mobile targets like iOS and Android using `gpui-mobile`), you typically use the standard `gpui::App` entry point and leverage its built-in executor.

GPUI does not use a traditional `#[tokio::main]` on the `main` function because it needs to control the platform's native event loop (UIKit on iOS, Looper on Android). Instead, you initialize the app and spawn async tasks within the `run` closure.

### Basic Async App Example

This example shows how to start a GPUI app and spawn an async task (e.g., a network request or timer) that updates the UI.

```rust
use gpui::*;[1][2][3][4][5][6][7]

struct HelloWorld {
    text: String,
}

impl Render for HelloWorld {
    fn render(&mut self, _cx: &mut ViewContext<Self>) -> impl IntoElement {
        div()
            .flex()
            .bg(rgb(0x2e7d32))
            .size_full()
            .justify_center()
            .items_center()
            .text_xl()
            .text_color(rgb(0xffffff))
            .child(self.text.clone())
    }
}

fn main() {
    // 1.[2][8] Initialize the Application
    Application::new().run(|cx: &mut AppContext| {
        // 2. Open a window
        cx.open_window(WindowOptions::default(), |cx| {
            // 3. Create a view
            let view = cx.new_view(|cx| {
                let view_handle = cx.view().downgrade();

                // 4. Spawn an async task
                cx.spawn(|mut cx| async move {
                    // Simulate async work (e.g., fetching data)
                    // Note: GPUI uses its own executor, but you can bridge to Tokio if needed.
                    Timer::after(std::time::Duration::from_secs(2)).await;

                    // 5. Update the UI from the async task
                    view_handle.update(&mut cx, |this, cx| {
                        this.text = "Async Task Complete!".to_string();
                        cx.notify();
                    }).ok();
                }).detach();

                HelloWorld {
                    text: "Waiting for async...".to_string(),
                }
            });
            view
        });
    });
}
```

### Key Async Concepts in GPUI
1.  **`cx.spawn(|cx| async move { ...[2][3] })`**: This is the primary way to run async code. It returns a `Task<T>`.[7] If you `detach()` it, it runs to completion; otherwise, it is cancelled when the `Task` handle is dropped.[7]
2.  **`WeakEntityHandle` / `view_handle.update(...)`**: Since async tasks run outside the synchronous render cycle, you must use a weak handle to safely update your view's state once the task finishes.
3.  **`gpui-mobile` Specifics**: When targeting mobile, your `main` function is often replaced or wrapped by platform-specific entry points (like `[no_mangle] extern "C" fn main` for Android or a Swift wrapper for iOS). However, the internal logic remains the same: `Application::new().run(...)`.
4.  **Tokio Integration**: If you need to use libraries that require a Tokio runtime (like `reqwest`), you can use the `gpui-tokio-bridge` crate or manually manage a Tokio runtime and use `cx.background_executor().spawn(...)` to bridge the two.

### Mobile Setup (Cargo.toml)
If you are specifically using the mobile-optimized fork or features:
```toml
[dependencies]
gpui = { git = "https://github.com/zed-industries/zed", package = "gpui" }
# Or if using the community mobile port
gpui-mobile = { git = "https://github.com/gpui-mobile/gpui-mobile" }
```

